def qsort(a, i, j):
    if i < j:
        k = particion(a, i, j)
        qsort(a, i, k - 1)
        qsort(a, k + 1, j)


def particion(a, i, j):
    # a[i] es el pivote.
    s = i
    for t in range(s, j):
        if a[t + 1] <= a[i]:
            (a[s + 1], a[t + 1]) = (a[t + 1], a[s + 1])
            s = s + 1
    (a[i], a[s]) = (a[s], a[i])
    return s
